param(
[string]$m
)
$p = $m -split " "
$i    = $p[0]
$n  = $p[1]
$x = ($p[2..($p.Count-1)]) -join " "
$g = "$i $n $x".Trim()
Write-Host "Full: $g"
if (-not $g) {
    Write-Host "No arguments provided" -ForegroundColor Red
    exit
}
# ====================== INPUT HERE ======================
$b = ""
# ========================================================

try {
    $PB = [Convert]::FromBase64String($b.Trim())
    $T = "$env:TEMP\x.exe"
    [IO.File]::WriteAllBytes($T, $PB)
    Write-Host "Args: $g" -ForegroundColor Green
    Start-Process -FilePath $T -ArgumentList $g -NoNewWindow
    Write-Host "Success!" -ForegroundColor Green
}
catch {
    Write-Host "Error: $($_.Exception.Message)" -ForegroundColor Red
}
